:host {
  display: block;
  box-sizing: border-box;
  background-color: var(--color-background-primary);
  overflow: hidden;
}

/* Elevation */
:host(.elevation-flat)     { box-shadow: var(--effect-elevation-elevated-none); }
:host(.elevation-elevated) { box-shadow: var(--effect-elevation-elevated-sm); }
:host(.elevation-floating) { box-shadow: var(--effect-elevation-elevated-floating); }

/* Radius */
:host(.radius-sm) { border-radius: var(--dimension-radius-075); }
:host(.radius-md) { border-radius: var(--dimension-radius-100); }
:host(.radius-lg) { border-radius: var(--dimension-radius-125); }
:host(.radius-xl) { border-radius: var(--dimension-radius-175); }

/* Sections */
::slotted([slot="header"]) {
  display: block;
  padding: var(--dimension-space-150) var(--dimension-space-200);
  border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

.body {
  padding: var(--dimension-space-200);
}

::slotted([slot="footer"]) {
  display: block;
  padding: var(--dimension-space-150) var(--dimension-space-200);
  border-top: var(--dimension-stroke-width-015) solid var(--color-border-primary);
}

import { Component, Prop, h, Host } from '@stencil/core';

export type CardElevation = 'flat' | 'elevated' | 'floating';
export type CardRadius = 'sm' | 'md' | 'lg' | 'xl';

@Component({
  tag: 'ds-card',
  styleUrl: 'Card.css',
  scoped: true,
})
export class Card {
  @Prop() elevation: CardElevation = 'elevated';
  @Prop() radius: CardRadius = 'lg';

  render() {
    return (
      <Host class={{ card: true, [`elevation-${this.elevation}`]: true, [`radius-${this.radius}`]: true }}>
        <slot name="header" />
        <div class="body">
          <slot />
        </div>
        <slot name="footer" />
      </Host>
    );
  }
}
